INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603597N$$, 2027, $$ATRT technologies provide essential development, assessment, and operational analysis capabilities to streamline testing and certification for both single systems
and systems of systems capabilities in order to reduce development time for new capabilities from years to weeks. Also, ATRT leverages support to refactoring,
development, and assessment of Artificial Intelligence / Machine Learning (AI/ML) aids with other applications to deliver warfighting capability. The integration of legacy
code and systems across the Naval warfighting portfolio aims to achieve an open integration and interoperability environment.

Project funding supports the development of enterprise level strategies and activities to apply ATA technologies to software-intensive acquisition programs. The
objectives include support for the Chief of Naval Operations' (CNO) vision outlined in the CNO's Navigation Plan (NAVPLAN) through continued development and
commercialization of ATRT Small Business Innovation Research (SBIR) technologies across the Navy enterprise. These SBIR derived technologies enable the Navy
enterprise to make rapid capability improvements through software updates while maintaining a continuous Authority to Operate (ATO) on a common digital warfighting
platform, and in enterprise sandbox technologies.$$, $$Automated Test and Re-Test (ATRT) capabilities enable faster and more consistent testing across the Naval enterprise. Specifically in the near term this project seeks to
implement ATRT into digital capabilities, laboratory testing, and the Overmatch Software Armory (OSA) DevSecOps environment to conduct secure system development
scalable distributed simulation. A seamless push to afloat, airborne, and edge infrastructure allowing the Navy's designated user community to make software updates
(new and modernization of old code) while maintaining, or eliminating, the need for an Authority to Operate (ATO). The Continuous Delivery/Continuous Integration (CD/
CI) of capability enabled by the ATRT technology for real time software code analysis and performance testing in the Cloud Development Environment (CDE) as well
as rapid feedback in the Operational Environment (OE). Enabling this effort, this program is developing and scaling the Integrated Modeling Environment (IME), which
supports shared and linked Model Based Systems Engineering (MBSE) from the mission level to the function/system level. This will in turn power the ATRT models
that analytically link together software code production output with intended planned capability developed against gaps filled at the mission level, enabling rapid and
continuous iteration and deployment of software into the digital environment.

