INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603609N$$, 2027, $$Most Navy munitions react violently when exposed to unplanned stimuli such as fire, shock and bullet or fragment impact, thus presenting a great hazard to ships,
aircraft and personnel. The Insensitive Munitions Advanced Development (IMAD) program (Project 0363) will provide, validate and transition technology to all new
weapon developments and priority weapon systems and enable production of munitions insensitive to these stimuli with no reduction in combat performance. Insensitive
Munitions (IM) is the Navy's focused effort on propellants, propulsion units, explosives, warheads, fuses and pyrotechnics to reduce the severity of cook-off and bullet/
fragment impact reactions, minimizing the probability for sympathetic detonation, both in normal storage and in use, increasing ship and platform survivability and
satisfying performance and readiness requirements.

 The Explosives Safety and Weapons Assessment (ES&WA) program (Project 0364) was a new start in FY 2025.$$, $$Reduce risk introduced by new weapons systems and technologies that have potential to interfere with ordnance safety and Fleet operations. Emerging radars for all
classes of ships introduce a heightened electromagnetic environment (EME) with the likelihood of exceeding the maximum allowable environment (MAE) currently in
place. The MAE provides the safety barrier in identifying the electrostatic safety threshold for ordnance items. Exceeding MAE introduces increased risk of inadvertent
detonation of electrically primed explosives.

